using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidences { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly ILogger<TicketClassifierService> _logger;

    public string[] CategoryLabels { get; }

    public TicketClassifierService(ILogger<TicketClassifierService> logger)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainAndEvaluate(dataView);

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract label names in score-array order
        var schema = _predictionEngine.OutputSchema;
        var scoreColumn = schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        CategoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    private ITransformer TrainAndEvaluate(IDataView dataView)
    {
        // Featurize text columns and combine with numeric Priority
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validate to produce meaningful metrics on a small dataset
        _logger.LogInformation("Training model with 3-fold cross-validation...");
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3);

        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            _logger.LogInformation(
                "Fold {Fold}: MacroAccuracy={MacroAccuracy:F4}  MicroAccuracy={MicroAccuracy:F4}  LogLoss={LogLoss:F4}",
                i + 1,
                result.Metrics.MacroAccuracy,
                result.Metrics.MicroAccuracy,
                result.Metrics.LogLoss);
        }

        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);

        _logger.LogInformation(
            "Average:  MacroAccuracy={MacroAccuracy:F4}  MicroAccuracy={MicroAccuracy:F4}  LogLoss={LogLoss:F4}",
            avgMacro, avgMicro, avgLogLoss);

        // Train final model on all data
        _logger.LogInformation("Training final model on full dataset...");
        return pipeline.Fit(dataView);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidences = CategoryLabels
            .Zip(prediction.Score, (label, score) => (label, score))
            .ToDictionary(x => x.label, x => x.score);

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidences = confidences
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }
}

